import{_ as r,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"96. Flexible Working Arrangements","description":"","frontmatter":{"title":"96. Flexible Working Arrangements","eba":"Allied Health Professionals 2021-2026","topics":["employment","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/workplace-rights/96-flexible-working-arrangements.md","filePath":"ebas/allied-health/workplace-rights/96-flexible-working-arrangements.md"}'),s={name:"ebas/allied-health/workplace-rights/96-flexible-working-arrangements.md"};function a(i,e,l,p,g,m){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_96-flexible-working-arrangements" tabindex="-1">96. Flexible Working Arrangements <a class="header-anchor" href="#_96-flexible-working-arrangements" aria-label="Permalink to &quot;96. Flexible Working Arrangements&quot;">​</a></h1><p><strong>96.1</strong> The Act entitles a specified Employee to request flexible working arrangements in specified circumstances.</p><p><strong>96.2</strong> A specified Employee is a:</p><p><strong>(a)</strong> full-time or part-time Employee with at least 12 months continuous service; and</p><p><strong>(b)</strong> long term casual Employee with a reasonable expectation of continuing employment by the Employer on a regular and systematic basis.</p><p><strong>96.3</strong> The specified circumstances are the Employee:</p><p><strong>(a)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger;</p><p><strong>(b)</strong> is a carer within the meaning of the Carer Recognition Act 2010 (Cth) caring for someone who has a disability, a medical condition (including a terminal or chronic illness), a mental illness or is frail or aged;</p><p><strong>(c)</strong> has a disability;</p><p><strong>(d)</strong> is 55 or older;</p><p><strong>(e)</strong> is experiencing violence from a member of the Employee’s family; or</p><p><strong>(f)</strong> provides care or support to a member of the Employee’s Immediate Family, who requires care or support because the member is experiencing violence or abuse from the member’s family.</p><p><strong>96.4</strong> A specified Employee may request the Employer for a change in working arrangements relating to the circumstances at subclause 96.3.</p><p><strong>96.5</strong> A request for a flexible work arrangement includes (but is not limited to) a request to work part-time upon return to work after taking leave for the birth or adoption of a child to assist the Employee to care for the child.</p><p><strong>96.6</strong> Changes in working arrangements may include but are not limited to hours of work, patterns of work and location of work.</p><p><strong>96.7</strong> The request by the Employee must be in writing, set out the change sought and reasons for the change.</p><p><strong>96.8</strong> The Employer must give the Employee a written response to the request within 21 days, stating whether the Employer grants or refuses the request. A request may only be refused on reasonable business grounds as described in the NES.</p><p><strong>96.9</strong> Where the Employer refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>96.10</strong> Where a request for flexible work arrangements is made, an Employee or Employer is entitled to meet with the other party to discuss:</p><p><strong>(a)</strong> the request;</p><p><strong>(b)</strong> an alternative to the request; or</p><p><strong>(c)</strong> reasons for a refusal on reasonable business grounds.</p><p><strong>96.11</strong> An Employee or Employer may choose to be represented at a meeting under subclause 96.10 by a representative including a Union or VHIA.</p><p><strong>96.12</strong> The dispute resolution procedure in the Agreement will apply to any dispute/grievance arising in relation to a request for flexible working arrangements, including a refusal on reasonable business grounds.</p><p><strong>96.13</strong> Other entitlements relevant to family violence can be found at <a href="/eba/ebas/allied-health/leave/66-family-violence-leave.html">clause 66</a> (Family Violence Leave).</p><p><strong>96.14</strong> Where an Employee wishes to end a flexible work arrangement in a manner other than as provided in the flexible work arrangements itself, this can occur by agreement between the Employee and the Employer, save that the Employer will not unreasonably withhold agreement.</p><p>Plain language terms: flex work, flexible hours, WFH.</p>',27)])])}const u=r(s,[["render",a]]);export{c as __pageData,u as default};
